SELECT c.name, c.city, SUM(od.quantity * p.unit_price) AS total_order_value FROM customers c JOIN orders o ON c.customer_id = o.customer_id JOIN order_details od ON o.order_id = od.order_id JOIN products p ON od.product_id = p.product_id WHERE c.city = 'Mumbai' GROUP BY c.name, c.city ORDER BY total_order_value DESC;
SELECT p.name, p.category, SUM(od.quantity) AS total_qty_sold FROM products p JOIN order_details od ON p.product_id = od.product_id GROUP BY p.name, p.category ORDER BY total_qty_sold DESC LIMIT 3;
SELECT sr.name, COUNT(DISTINCT o.customer_id) AS unique_customers FROM sales_reps sr JOIN orders o ON sr.sales_rep_id = o.sales_rep_id GROUP BY sr.name ORDER BY unique_customers DESC;
SELECT o.order_id, o.order_date, c.name, SUM(od.quantity * p.unit_price) AS order_value FROM orders o JOIN customers c ON o.customer_id = c.customer_id JOIN order_details od ON o.order_id = od.order_id JOIN products p ON od.product_id = p.product_id GROUP BY o.order_id, o.order_date, c.name HAVING SUM(od.quantity * p.unit_price) > 10000 ORDER BY order_value DESC;
SELECT p.name, p.category FROM products p LEFT JOIN order_details od ON p.product_id = od.product_id WHERE od.product_id IS NULL;
